# Prompt: Build a Python Flask file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from flask import Flask, jsonify, send_file, abort
import os
import stat

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
ROOT_DIR = os.path.abspath(UPLOAD_FOLDER)

@app.route('/files/<path:rel_path>', methods=['GET'])
def list_directory(rel_path):
    try:
        # Normalize the path to handle '..' and clean up
        normalized_path = os.path.normpath(os.path.join(ROOT_DIR, rel_path))
        
        # Ensure the path is within the upload directory
        if not normalized_path.startswith(ROOT_DIR):
            abort(403)
        
        if not os.path.exists(normalized_path):
            abort(404)
            
        if not os.path.isdir(normalized_path):
            abort(400)
            
        files = []
        for item in os.listdir(normalized_path):
            item_path = os.path.join(normalized_path, item)
            item_stat = os.stat(item_path)
            
            file_info = {
                'name': item,
                'is_dir': os.path.isdir(item_path),
                'size': item_stat.st_size,
                'modified': item_stat.st_mtime
            }
            files.append(file_info)
            
        return jsonify({'files': files})
        
    except Exception as e:
        abort(500)

@app.route('/download/<path:rel_path>', methods=['GET'])
def download_file(rel_path):
    try:
        # Normalize the path to handle '..' and clean up
        normalized_path = os.path.normpath(os.path.join(ROOT_DIR, rel_path))
        
        # Ensure the path is within the upload directory
        if not normalized_path.startswith(ROOT_DIR):
            abort(403)
            
        if not os.path.exists(normalized_path):
            abort(404)
            
        if os.path.isdir(normalized_path):
            abort(400)
            
        return send_file(normalized_path, as_attachment=True)
        
    except Exception as e:
        abort(500)

@app.route('/info/<path:rel_path>', methods=['GET'])
def get_file_info(rel_path):
    try:
        # Normalize the path to handle '..' and clean up
        normalized_path = os.path.normpath(os.path.join(ROOT_DIR, rel_path))
        
        # Ensure the path is within the upload directory
        if not normalized_path.startswith(ROOT_DIR):
            abort(403)
            
        if not os.path.exists(normalized_path):
            abort(404)
            
        stat_info = os.stat(normalized_path)
        
        file_info = {
            'name': os.path.basename(normalized_path),
            'path': normalized_path,
            'is_dir': os.path.isdir(normalized_path),
            'size': stat_info.st_size,
            'created': stat_info.st_ctime,
            'modified': stat_info.st_mtime,
            'permissions': oct(stat_info.st_mode)[-3:]
        }
        
        return jsonify(file_info)
        
    except Exception as e:
        abort(500)

if __name__ == '__main__':
    if not os.path.exists(UPLOAD_FOLDER):
        os.makedirs(UPLOAD_FOLDER)
    app.run(debug=True)